/* can_bus.h - CAN Bus Driver */
#ifndef CAN_BUS_H
#define CAN_BUS_H

#include <stdint.h>

#define CAN_MAX_DLC  8U

typedef struct {
    uint32_t id;            /* CAN identifier */
    uint8_t  is_extended;   /* MOVED: 1 = 29-bit ID, 0 = 11-bit ID */
    uint8_t  is_remote;     /* MOVED: 1 = Remote Frame */
    uint8_t  dlc;           /* Data length code (0-8) */
    uint8_t  padding;       /* Explicit padding for alignment */
    uint8_t  data[CAN_MAX_DLC];
    uint32_t timestamp_us;  /* NEW: reception timestamp in microseconds */
} can_frame_t;

typedef void (*can_rx_cb_t)(const can_frame_t *frame);

int  can_init(uint8_t channel, uint32_t bitrate);
int  can_send(uint8_t channel, const can_frame_t *frame);
int  can_set_rx_callback(uint8_t channel, can_rx_cb_t cb);
void can_deinit(uint8_t channel);

#endif /* CAN_BUS_H */

